let SearchPageVisits =
    pageViews
    | where timestamp {TimeRange}
    | where url contains "/search"
    | summarize by operation_Id;
let TotalVisits = toscalar(SearchPageVisits | count);
let ClosedIncludedVisits = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where tostring(customDimensions.excludeClosedCases) == "false"
    | project operation_Id
    | join kind=inner SearchPageVisits on operation_Id
    | summarize by operation_Id
    | count
);
print
    TotalVisits = TotalVisits,
    ClosedIncludedVisits = ClosedIncludedVisits,
    IncludeClosedRate = round(iif(TotalVisits > 0, todouble(ClosedIncludedVisits) / todouble(TotalVisits) * 100, 0.0), 1)

