let SearchPageVisits =
    pageViews
    | where timestamp {TimeRange}
    | where url contains "/search"
    | summarize by operation_Id;
let TotalVisits = toscalar(SearchPageVisits | count);
// Proxy: case number search with excludeClosedCases=true that returns no open results
// We detect this via searches where excludeClosedCases=true + caseNumber is set,
// then a subsequent search in same session with excludeClosedCases=false (user acted on the hint)
let HintActedVisits = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isnotempty(tostring(customDimensions.caseNumber))
    | summarize
        hadExcluded = countif(tostring(customDimensions.excludeClosedCases) == "true"),
        thenIncluded = countif(tostring(customDimensions.excludeClosedCases) == "false")
        by operation_Id
    | where hadExcluded > 0 and thenIncluded > 0
    | join kind=inner SearchPageVisits on operation_Id
    | count
);
print
    TotalVisits = TotalVisits,
    HintActedVisits = HintActedVisits,
    HintActedRate = round(iif(TotalVisits > 0, todouble(HintActedVisits) / todouble(TotalVisits) * 100, 0.0), 1)
